// Unit 4, ¡A Comer!
// Food & Drink

export default {n:4,lang:"es",srcLang:"en",track:"v2",title:"¡A Comer!",sub:"Food & Drink",icon:"🍽️",level:"A1.2",color:"#7B5EE8",lessons:[
  {id:"esp4l1",title:"Comida Básica",icon:"🍞",xp:15,board:true,steps:[
        {type:"intro",title:"Comida Básica",desc:"Learn the essential food words you will need every day in Spanish.",goals:["Name basic foods in Spanish","Use el/la correctly with food nouns","Understand the special case of el agua"]},
        {type:"teach",trg:"la manzana",src:"the apple",pos:"noun",gender:"f",phonetic:"man-SAH-nah",note:"Feminine noun. Plural: las manzanas.",example:"A: ¿Te gustan las manzanas?\nB: Sí, me gustan mucho.",exampleSrc:"A: Do you like apples?\nB: Yes, I like them a lot.",funFact:"Apple. From Arabic 'manzana' or Latin 'mala matiana' (Matian apple, named for a Roman writer). Same word also means 'city block' in Spanish; the blocks look like apple sections."},
        {type:"teach",trg:"el plátano",src:"the banana",pos:"noun",gender:"m",phonetic:"PLAH-tah-noh",note:"Masculine noun. Also called 'la banana' in some countries.",example:"A: ¿Quieres un plátano?\nB: Sí, por favor.",exampleSrc:"A: Do you want a banana?\nB: Yes, please.",funFact:"Banana/plantain. Spanish uses 'plátano' for both sweet bananas and starchy cooking plantains; Latin America distinguishes: banana vs plátano. From Greek 'platys' (broad/flat leaf)."},
        {type:"teach",trg:"la naranja",src:"the orange",pos:"noun",gender:"f",phonetic:"nah-RAHN-hah",note:"Feminine. The fruit and the color share the same word.",example:"A: ¿De qué color es la naranja?\nB: La naranja es naranja.",exampleSrc:"A: What color is the orange?\nB: The orange is orange.",funFact:"Orange (fruit). From Arabic 'nāranj' via Persian 'nārang' from Sanskrit 'nāraṅga.' Islamic trade brought the fruit and the name to Spain. Same journey for many food words."},
        {type:"teach",trg:"la fresa",src:"the strawberry",pos:"noun",gender:"f",phonetic:"FREH-sah",note:"Feminine. Plural: las fresas.",example:"A: ¿Qué fruta te gusta más?\nB: Me gustan las fresas.",exampleSrc:"A: What fruit do you like most?\nB: I like strawberries.",funFact:"Strawberry. From French 'fraise.' Spain also uses 'frutilla' in some regions. 'Fresa' also means 'strawberry-blonde' as an adjective."},
        {type:"teach",trg:"la uva",src:"the grape",pos:"noun",gender:"f",phonetic:"OO-bah",note:"Feminine. Almost always used in plural: las uvas.",example:"A: ¿Quieres uvas?\nB: No, gracias. No me gustan las uvas.",exampleSrc:"A: Do you want grapes?\nB: No, thanks. I don't like grapes.",funFact:"Grape. From Latin 'uva.' Almost always used in plural; you rarely eat one grape. Famous New Year tradition: eat 12 grapes at midnight (one for each strike)."},
        {type:"teach",trg:"el limón",src:"the lemon / lime",pos:"noun",gender:"m",phonetic:"lee-MOHN",note:"Masculine. In most of Latin America, limón refers to lime.",example:"A: ¿Tienes limones?\nB: Sí, tengo tres limones.",exampleSrc:"A: Do you have lemons?\nB: Yes, I have three lemons.",funFact:"Lemon/lime. From Arabic 'laymūn.' In Spain and most of Latin America, 'limón' usually means the yellow lemon. Mexico and parts of Central America use 'limón' for green lime."},
        {type:"tip",title:"Me gusta vs Me gustan",text:"Me gusta + singular noun:\nMe gusta la manzana.\n\nMe gustan + plural noun:\nMe gustan las fresas.\n\nThe verb agrees with what you LIKE, not with you.",icon:"💡"},
        {type:"mc",q:"How do you say 'I like strawberries'?",opts:["Me gustan las fresas","Me gusta las fresas","Yo gusto las fresas","Me gusta la fresa"],ans:"Me gustan las fresas",hint:"___ is plural, so the verb must match."},
        {type:"fb",opts:["gustan","gusta","gusto","gustas"],hint:"Naranjas is plural. The verb agrees with what is liked.",s:"¿Te {1} las naranjas?",a:"gustan"},
        {type:"mc",q:"What is 'el plátano'?",opts:["the apple","the banana","the orange","the grape"],ans:"the banana",hint:"This yellow fruit is popular in tropical countries."},
        {type:"match",pairs:[{trg:"la manzana",src:"apple"},{trg:"el plátano",src:"banana"},{trg:"la naranja",src:"orange"},{trg:"la fresa",src:"strawberry"},{trg:"la uva",src:"grape"}]},
        {type:"fb",opts:["gusta","gustan","gusto","gustas"],hint:"Limón is singular. The verb agrees with the thing liked.",s:"No me {1} el limón.",a:"gusta"},
        {type:"mc",q:"Which fruit is feminine?",opts:["el limón","el plátano","la fresa","el durazno"],ans:"la fresa",hint:"Look for the article 'la' before the noun."},
        {type:"drag_fill",hint:"Plural fruit uses gustan. Singular fruit uses gusta.",s:"A mí me {1} las {2} pero no me {3} el {4}.",blanks:{"1":"gustan","2":"uvas","3":"gusta","4":"limón"},pool:["gustan","uvas","gusta","limón","manzana","gustas"]},
        {type:"mc",q:"'La naranja es naranja' means:",opts:["The orange is sweet","The orange is red","I like oranges","The orange is orange"],ans:"The orange is orange",hint:"The same word names both the fruit and its color."},
        {type:"fb",opts:["gusta","gustan","gusto","gustas"],hint:"Manzana is singular, so the verb takes singular form.",s:"Me {1} mucho la manzana.",a:"gusta"},
        {type:"mc",q:"How do you say 'I don't like grapes'?",opts:["No me gustan las uvas","No me gusta las uvas","Me no gustan las uvas","No gusto las uvas"],ans:"No me gustan las uvas",hint:"Put 'no' before 'me ___'. ___ is plural."}
  ]},
  {id:"esp4l2",title:"Las Verduras",icon:"🥦",xp:15,board:true,steps:[
        {type:"intro",title:"Las Verduras",desc:"Learn vegetables and practice talking about food preferences.",goals:["Name 6 common vegetables","Use querer (to want)","Express food preferences"]},
        {type:"teach",trg:"la verdura",src:"the vegetable",pos:"noun",gender:"f",phonetic:"ber-DOO-rah",note:"Feminine. General term for all vegetables.",example:"A: ¿Te gustan las verduras?\nB: Sí, como verduras todos los días.",exampleSrc:"A: Do you like vegetables?\nB: Yes, I eat vegetables every day.",funFact:"Vegetable. From Latin 'viridis' (green). 'Verde' (green) is the same root. 'Verduras' covers all green vegetables; 'vegetales' is a broader anglicism."},
        {type:"teach",trg:"el tomate",src:"the tomato",pos:"noun",gender:"m",phonetic:"toh-MAH-teh",note:"Masculine. Key ingredient in Spanish cooking.",example:"A: ¿Quieres tomate en la ensalada?\nB: Sí, me gusta el tomate.",exampleSrc:"A: Do you want tomato in the salad?\nB: Yes, I like tomato.",funFact:"Cognate with English 'tomato'. Spanish and English share many Latin-derived words."},
        {type:"teach",trg:"la lechuga",src:"the lettuce",pos:"noun",gender:"f",phonetic:"leh-CHOO-gah",note:"Feminine. Base of most salads.",example:"A: ¿Qué necesitamos para la ensalada?\nB: Necesitamos lechuga y tomate.",exampleSrc:"A: What do we need for the salad?\nB: We need lettuce and tomato.",funFact:"Lettuce. From Latin 'lactuca,' from 'lac' (milk); named because it oozes milky sap when cut. English 'lettuce' shares the root. All milk-vegetable."},
        {type:"teach",trg:"la cebolla",src:"the onion",pos:"noun",gender:"f",phonetic:"seh-BOH-yah",note:"Feminine. The 'll' sounds like 'y' in most dialects.",example:"A: ¿Te gusta la cebolla?\nB: No mucho. Me hace llorar.",exampleSrc:"A: Do you like onion?\nB: Not much. It makes me cry.",funFact:"Onion. From Latin 'cepulla' (small onion). Related to English 'chive' (same Indo-European root). Cooking base across the Spanish-speaking world."},
        {type:"teach",trg:"el ajo",src:"the garlic",pos:"noun",gender:"m",phonetic:"AH-hoh",note:"Masculine. Essential in Spanish and Latin American cooking.",example:"A: ¿Cuánto ajo pongo?\nB: Pon mucho ajo, por favor.",exampleSrc:"A: How much garlic should I put?\nB: Put a lot of garlic, please.",funFact:"Garlic. From Latin 'allium.' Same root as English 'allium' (the plant genus). Spanish cuisine uses ajo constantly: gambas al ajillo, sopa de ajo, alioli (garlic sauce)."},
        {type:"teach",trg:"la patata",src:"the potato",pos:"noun",gender:"f",phonetic:"pah-TAH-tah",note:"Feminine. In Latin America: la papa.",example:"A: ¿Quieres patatas fritas?\nB: ¡Sí! Me encantan las patatas fritas.",exampleSrc:"A: Do you want french fries?\nB: Yes! I love french fries.",funFact:"Cognate with English 'potato'. Spanish and English share many Latin-derived words."},
        {type:"teach",trg:"quiero",src:"I want",pos:"verb",gender:null,phonetic:"kee-EH-roh",note:"From querer. Stem changes: quiero, quieres, quiere, queremos, quieren.",example:"A: ¿Qué quieres comer?\nB: Quiero una ensalada, por favor.",exampleSrc:"A: What do you want to eat?\nB: I want a salad, please.",funFact:"From 'querer' (to want / to love). Stem change: e→ie in yo/tu/el/ella/ellos forms. Also means 'I love' romantically. 'Te quiero' = I love you (gentler than 'te amo')."},
        {type:"tip",title:"Querer: A Stem-Changing Verb",text:"Querer (to want) changes e to ie in most forms:\nyo quiero\ntú quieres\nél/ella quiere\nnosotros queremos (no change!)\nellos quieren\n\nThis e→ie pattern is very common in Spanish.",icon:"📝"},
        {type:"mc",q:"What is 'la cebolla'?",opts:["the onion","the garlic","the potato","the tomato"],ans:"the onion",hint:"This vegetable can make you cry when you cut it."},
        {type:"fb",opts:["quiero","quieres","quiere","queremos"],hint:"The subject is 'yo'. Find the matching form of querer.",s:"Yo {1} una ensalada de tomate.",a:"quiero"},
        {type:"match",pairs:[{trg:"el tomate",src:"tomato"},{trg:"la lechuga",src:"lettuce"},{trg:"la cebolla",src:"onion"},{trg:"el ajo",src:"garlic"},{trg:"la patata",src:"potato"}]},
        {type:"mc",q:"Which form completes: 'Ella ___ patatas fritas.'?",opts:["quiero","quiere","quieres","queremos"],ans:"quiere",hint:"Ella is third person singular. The stem changes e to ie."},
        {type:"fb",opts:["gustan","gusta","gusto","gustas"],hint:"Verduras is plural. The verb agrees with what is liked.",s:"¿Te {1} las verduras?",a:"gustan"},
        {type:"mc",q:"In Latin America, 'la patata' is called:",opts:["el patato","la batata","la papa","la papata"],ans:"la papa",hint:"A shorter word used across Latin America for potato."},
        {type:"drag_fill",hint:"'I want' + salad ingredients from the lesson.",s:"{1} una ensalada con {2} y {3}.",blanks:{"1":"Quiero","2":"lechuga","3":"tomate"},pool:["Quiero","lechuga","tomate","quieres","cebolla","patata"]},
        {type:"fb",opts:["ajo","uva","fresa","limón"],hint:"This small but strong ingredient is essential in Spanish cooking.",s:"El {1} es muy importante en la cocina española.",a:"ajo"},
        {type:"mc",q:"'Nosotros queremos' means:",opts:["I want","they want","you want","we want"],ans:"we want",hint:"Nosotros is 'we'. Note: no stem change in this form."}
  ]},
  {id:"esp4l3",title:"Las Bebidas",icon:"🥤",xp:15,board:true,steps:[
        {type:"intro",title:"Las Bebidas",desc:"Learn drinks and how to order at a café.",goals:["Name 6 common drinks","Order a drink politely","Use 'un/una' with drinks"]},
        {type:"teach",trg:"el agua",src:"the water",pos:"noun",gender:"m",phonetic:"AH-gwah",note:"Feminine meaning but uses 'el' (el agua) to avoid 'la a-' clash. Plural: las aguas.",example:"A: ¿Qué quieres beber?\nB: Quiero un vaso de agua, por favor.",exampleSrc:"A: What do you want to drink?\nB: I want a glass of water, please.",funFact:"Water. A grammatical curiosity: 'agua' is feminine but uses 'el' in singular (el agua, not 'la agua') because of the stressed 'a' at start. In plural reverts: las aguas. One of Spanish's quirkier rules."},
        {type:"teach",trg:"el café",src:"the coffee",pos:"noun",gender:"m",phonetic:"kah-FEH",note:"Masculine. Café con leche = coffee with milk. Very common in Spain.",example:"A: ¿Tomas café por la mañana?\nB: Sí, siempre tomo café con leche.",exampleSrc:"A: Do you have coffee in the morning?\nB: Yes, I always have coffee with milk.",funFact:"Coffee. From Arabic 'qahwah' via Turkish/Italian. Spanish café culture is foundational; 'tomar un café' is a social ritual, not just a beverage. Accent on é preserves the French 'café' pronunciation."},
        {type:"teach",trg:"el té",src:"the tea",pos:"noun",gender:"m",phonetic:"TEH",note:"Masculine. Written with accent: té (without accent, 'te' means 'you').",example:"A: ¿Quieres té o café?\nB: Prefiero té, gracias.",exampleSrc:"A: Do you want tea or coffee?\nB: I prefer tea, thanks.",funFact:"Tea. Accent distinguishes 'té' (tea) from 'te' (pronoun, you). Latin America drinks more tea than Spain does. Spain strongly prefers coffee; tea is often perceived as English/British."},
        {type:"teach",trg:"la leche",src:"the milk",pos:"noun",gender:"f",phonetic:"LEH-cheh",note:"Feminine. Very common in café con leche and desserts.",example:"A: ¿Hay leche en la nevera?\nB: No, necesitamos comprar leche.",exampleSrc:"A: Is there milk in the fridge?\nB: No, we need to buy milk.",funFact:"Milk. From Latin 'lac/lactis.' Spanish modified to 'leche.' Same root as English 'lactose,' 'lactation.' Also slang for 'really great' or 'damn' (positive or negative) in Spain."},
        {type:"teach",trg:"el zumo",src:"the juice",pos:"noun",gender:"m",phonetic:"THOO-moh",note:"Masculine. In Latin America: el jugo.",example:"A: ¿Quieres un zumo de naranja?\nB: Sí, me encanta el zumo de naranja.",exampleSrc:"A: Do you want an orange juice?\nB: Yes, I love orange juice.",funFact:"Juice (Spain). Latin America says 'jugo.' Same word, different regions. 'Zumo' from Greek via Arabic. The word choice instantly marks Spanish vs Latin American speech."},
        {type:"teach",trg:"la cerveza",src:"the beer",pos:"noun",gender:"f",phonetic:"ser-BEH-sah",note:"Feminine. C before e = 's' sound in Latin America, 'th' in Spain.",example:"A: ¿Tomamos una cerveza?\nB: ¡Buena idea! Una cerveza, por favor.",exampleSrc:"A: Shall we have a beer?\nB: Good idea! A beer, please.",funFact:"Beer. From Latin 'cervisia' (beer, Gaulish origin). Spanish kept the Latin word; Portuguese 'cerveja' and French 'cervoise' share it. English went a different way with 'beer.'"},
        {type:"tip",title:"Ordering Drinks",text:"To order:\nUn café, por favor. (masc)\nUna cerveza, por favor. (fem)\n\nUn/una = a/an.\nUn before masculine nouns.\nUna before feminine nouns.\n\n¿Me pone...? = Could you give me...? (polite, Spain)",icon:"☕"},
        {type:"mc",q:"Why do we say 'el agua' instead of 'la agua'?",opts:["To avoid two 'a' sounds together","Because agua is masculine","Because all drinks use el","It's a grammar exception with no rule"],ans:"To avoid two 'a' sounds together",hint:"Spanish ___s la + a- at the start of a word."},
        {type:"fb",opts:["un","una","el","la"],hint:"Café is masculine. Use the masculine indefinite article.",s:"Quiero {1} café con leche.",a:"un"},
        {type:"match",pairs:[{trg:"el agua",src:"water"},{trg:"el café",src:"coffee"},{trg:"el té",src:"tea"},{trg:"la leche",src:"milk"},{trg:"la cerveza",src:"beer"}]},
        {type:"mc",q:"How do you order a beer politely?",opts:["Un cerveza, por favor","Una cerveza, por favor","La cerveza, por favor","Cerveza me da"],ans:"Una cerveza, por favor",hint:"___ is feminine. Use '…' and add 'por ___'."},
        {type:"fb",opts:["zumo","agua","leche","cerveza"],hint:"The orange version of this drink is a breakfast staple.",s:"¿Quieres {1} de naranja?",a:"zumo"},
        {type:"mc",q:"In Latin America, 'el zumo' is called:",opts:["la zuma","el sumo","el jugo","el zugo"],ans:"el jugo",hint:"A different word for juice used across Latin America."},
        {type:"drag_fill",hint:"Order coffee (masc) with milk, politely.",s:"Para mí, {1} café con {2}, por {3}.",blanks:{"1":"un","2":"leche","3":"favor"},pool:["un","leche","favor","una","agua","gracias"]},
        {type:"fb",opts:["leche","café","zumo","té"],hint:"This white drink is kept cold in the fridge.",s:"¿Hay {1} en la nevera?",a:"leche"},
        {type:"mc",q:"Which drink is feminine?",opts:["el zumo","el café","el té","la cerveza"],ans:"la cerveza",hint:"Look for the article 'la' before the noun."},
        {type:"mc",q:"How do you say 'I want tea, please'?",opts:["Quiero té, por favor","Quiero el té, por favor","Yo quiere té","Me gusta té, por favor"],ans:"Quiero té, por favor",hint:"Use ___ + the drink name. No article needed when ordering."}
  ]},
  {id:"esp4l4",title:"La Comida",icon:"🍲",xp:15,board:true,steps:[
        {type:"intro",title:"La Comida",desc:"Learn basic meal foods and express hunger and thirst.",goals:["Name common meal foods","Use tener hambre / tener sed","Talk about meals of the day"]},
        {type:"teach",trg:"el pan",src:"the bread",pos:"noun",gender:"m",phonetic:"PAHN",note:"Masculine. A staple at every Spanish meal.",example:"A: ¿Quieres pan con mantequilla?\nB: Sí, me gusta el pan fresco.",exampleSrc:"A: Do you want bread with butter?\nB: Yes, I like fresh bread.",funFact:"Bread. From Latin 'panis.' Core food word; also figurative: 'pan de cada día' (daily bread, everyday thing), 'ser pan comido' (to be a piece of cake, literally 'bread eaten')."},
        {type:"teach",trg:"el arroz",src:"the rice",pos:"noun",gender:"m",phonetic:"ah-RROHS",note:"Masculine. Base of paella and many Latin American dishes.",example:"A: ¿Qué comes con el pollo?\nB: Como arroz con pollo.",exampleSrc:"A: What do you eat with chicken?\nB: I eat rice with chicken.",funFact:"Rice. From Arabic 'al-ruz.' Islamic trade brought rice to Spain. Paella valenciana and countless regional dishes descend from that introduction. 'Arroz' with accent-free z sound."},
        {type:"teach",trg:"el pollo",src:"the chicken",pos:"noun",gender:"m",phonetic:"POH-yoh",note:"Masculine. The 'll' sounds like 'y'.",example:"A: ¿Te gusta el pollo?\nB: Sí, como pollo casi todos los días.",exampleSrc:"A: Do you like chicken?\nB: Yes, I eat chicken almost every day.",funFact:"Chicken. From Latin 'pullus' (young animal). Originally any young animal; Spanish narrowed it to chicken. Also slang for 'a kid/young person' in some LATAM countries."},
        {type:"teach",trg:"el pescado",src:"the fish (food)",pos:"noun",gender:"m",phonetic:"pes-KAH-doh",note:"Masculine. El pez = live fish. El pescado = fish as food.",example:"A: ¿Prefieres carne o pescado?\nB: Prefiero el pescado.",exampleSrc:"A: Do you prefer meat or fish?\nB: I prefer fish.",funFact:"Fish (as food). From 'pescar' (to fish). Compare 'el pez' (living fish). Spanish makes this distinction: pez swims, pescado is served. English has one word for both."},
        {type:"teach",trg:"la carne",src:"the meat",pos:"noun",gender:"f",phonetic:"KAR-neh",note:"Feminine. General term for all meat.",example:"A: ¿Comes carne?\nB: No, soy vegetariano.",exampleSrc:"A: Do you eat meat?\nB: No, I'm vegetarian.",funFact:"Meat/flesh. From Latin 'caro/carnis.' Same root as English 'carnivore,' 'carnal,' 'carnival' (originally 'farewell to meat' before Lent)."},
        {type:"teach",trg:"tener hambre",src:"to be hungry",pos:"verb",gender:null,phonetic:"teh-NER AHM-breh",note:"Literally 'to have hunger'. Spanish uses tener, not ser/estar.",example:"A: ¿Tienes hambre?\nB: Sí, tengo mucha hambre.",exampleSrc:"A: Are you hungry?\nB: Yes, I'm very hungry.",funFact:"Literally 'to have hunger.' Spanish frames physical states as possessions: tener hambre (hungry), tener sed (thirsty), tener miedo (afraid). English uses 'be'; Spanish uses 'have.'"},
        {type:"teach",trg:"tener sed",src:"to be thirsty",pos:"verb",gender:null,phonetic:"teh-NER SED",note:"Literally 'to have thirst'. Use mucha sed for 'very thirsty'.",example:"A: Tengo sed. ¿Hay agua?\nB: Sí, hay agua en la nevera.",exampleSrc:"A: I'm thirsty. Is there water?\nB: Yes, there's water in the fridge.",funFact:"'To have thirst.' Part of the tener-family for physical sensations. Also: tener frío (cold), tener calor (hot). Never 'estar frío' for feeling cold; that describes an object being cold to touch."},
        {type:"tip",title:"Tener Expressions",text:"Spanish uses 'tener' (to have) where English uses 'to be':\ntener hambre = to be hungry\ntener sed = to be thirsty\ntener frío = to be cold\ntener calor = to be hot\ntener sueño = to be sleepy\n\nUse mucho/mucha for 'very':\nTengo mucha hambre. (hambre is feminine)",icon:"💡"},
        {type:"mc",q:"How do you say 'I'm hungry' in Spanish?",opts:["Tengo hambre","Soy hambre","Estoy hambre","Tengo hambrito"],ans:"Tengo hambre",hint:"Spanish uses 'to have hunger', not 'to be hungry'."},
        {type:"fb",opts:["Tienes","Tengo","Tiene","Tenemos"],hint:"Asking 'you' (informal) if they have thirst.",s:"¿{1} sed? Hay agua en la nevera.",a:"Tienes"},
        {type:"match",pairs:[{trg:"el pan",src:"bread"},{trg:"el arroz",src:"rice"},{trg:"el pollo",src:"chicken"},{trg:"la carne",src:"meat"},{trg:"el pescado",src:"fish"}]},
        {type:"mc",q:"What is the difference between 'el pez' and 'el pescado'?",opts:["Pez is big, pescado is small","Pez is alive, pescado is food","Pez is sea fish, pescado is river fish","They are the same"],ans:"Pez is alive, pescado is food",hint:"One swims, the other is on your plate."},
        {type:"fb",opts:["hambre","sed","sueño","calor"],hint:"You want to eat, so you're feeling this.",s:"Tengo mucha {1}. Quiero comer.",a:"hambre"},
        {type:"mc",q:"Which form of 'I am very hungry' is grammatically correct in Spanish?",opts:["Tengo muy hambre","Tengo mucho hambre","Tengo mucha hambre","Tengo hambre mucho"],ans:"Tengo mucha hambre",hint:"The noun for hunger is feminine, so the intensifier must agree in gender."},
        {type:"drag_fill",hint:"Express hunger and name a classic rice dish.",s:"Tengo {1}. Quiero {2} con {3}.",blanks:{"1":"hambre","2":"arroz","3":"pollo"},pool:["hambre","arroz","pollo","sed","pan","carne"]},
        {type:"fb",opts:["pollo","agua","leche","zumo"],hint:"This common protein sounds like POH-yoh.",s:"Como {1} casi todos los días.",a:"pollo"},
        {type:"mc",q:"Translate: '¿Quieres pan con mantequilla?'",opts:["I want bread with butter","Do you like bread and butter?","Is there bread with butter?","Do you want bread with butter?"],ans:"Do you want bread with butter?",hint:"¿Quieres...? is asking if you ___ something."}
  ]},
  {id:"esp4l5",title:"El Desayuno",icon:"🥐",xp:15,board:true,steps:[
        {type:"intro",title:"El Desayuno",desc:"Learn breakfast foods and describe what you eat in the morning.",goals:["Name breakfast items","Use tomar/desayunar","Describe your breakfast"]},
        {type:"teach",trg:"el desayuno",src:"the breakfast",pos:"noun",gender:"m",phonetic:"deh-sah-YOO-noh",note:"Masculine. From des- (un-) + ayuno (fasting). Breaking the fast!",example:"A: ¿Qué tomas para el desayuno?\nB: Tomo café con tostadas.",exampleSrc:"A: What do you have for breakfast?\nB: I have coffee with toast.",funFact:"Breakfast. From 'des-' (un-) + 'ayuno' (fast). Parallel to English 'break + fast.' Both languages inherited the same metaphor from Latin: unfasting after the overnight fast."},
        {type:"teach",trg:"la tostada",src:"the toast",pos:"noun",gender:"f",phonetic:"tohs-TAH-dah",note:"Feminine. Tostadas con tomate is a classic Spanish breakfast.",example:"A: ¿Quieres tostadas con tomate?\nB: Sí, con tomate y aceite de oliva.",exampleSrc:"A: Do you want toast with tomato?\nB: Yes, with tomato and olive oil.",funFact:"Toast. From Latin 'tostus' (toasted). Spanish 'tostada' is a breakfast staple; toasted bread with olive oil and tomato in Spain, or fried tortilla in Mexico."},
        {type:"teach",trg:"el huevo",src:"the egg",pos:"noun",gender:"m",phonetic:"WEH-boh",note:"Masculine. The H is silent. Plural: los huevos.",example:"A: ¿Cómo quieres los huevos?\nB: Quiero huevos con tostada, por favor.",exampleSrc:"A: How do you want the eggs?\nB: I want eggs with toast, please.",funFact:"Egg. From Latin 'ovum.' The h is silent, a leftover from Latin. 'Huevo' is the basic word; 'yema' is yolk, 'clara' is white. Spanish cuisine has many egg idioms."},
        {type:"teach",trg:"el cereal",src:"the cereal",pos:"noun",gender:"m",phonetic:"seh-reh-AHL",note:"Masculine. A cognate! Same meaning as in English.",example:"A: ¿Desayunas cereal?\nB: Sí, cereal con leche.",exampleSrc:"A: Do you have cereal for breakfast?\nB: Yes, cereal with milk.",funFact:"Cognate with English 'cereal'. Spanish and English share many Latin-derived words."},
        {type:"teach",trg:"la mermelada",src:"the jam / marmalade",pos:"noun",gender:"f",phonetic:"mer-meh-LAH-dah",note:"Feminine. Cognate of English 'marmalade'.",example:"A: ¿Hay mermelada de fresa?\nB: Sí, está en la mesa.",exampleSrc:"A: Is there strawberry jam?\nB: Yes, it's on the table.",funFact:"Jam. From Portuguese 'marmelada' (quince jam), from 'marmelo' (quince). Originally only quince, now any fruit preserve. English 'marmalade' narrowed to citrus only."},
        {type:"teach",trg:"desayunar",src:"to have breakfast",pos:"verb",gender:null,phonetic:"deh-sah-yoo-NAR",note:"Regular -ar verb: desayuno, desayunas, desayuna, desayunamos.",example:"A: ¿A qué hora desayunas?\nB: Desayuno a las ocho.",exampleSrc:"A: What time do you have breakfast?\nB: I have breakfast at eight.",funFact:"From 'des-' (un-) + 'ayunar' (to fast). Literally 'to unfast,' mirroring English 'breakfast' = break + fast. The shared metaphor is ancient: Romans already described the morning meal this way."},
        {type:"tip",title:"Spanish Breakfast Culture",text:"Spanish breakfast is typically light:\nCafé con leche + tostadas (toast)\nOften with aceite de oliva y tomate.\n\nBigger breakfasts:\nChurros con chocolate (a treat!)\nBocadillo (sandwich on baguette)\n\nBreakfast is the smallest meal.\nLunch (la comida) is the main meal, eaten around 2-3 PM.",icon:"🇪🇸"},
        {type:"mc",q:"What does 'desayuno' literally mean?",opts:["Breaking the fast","Morning food","First meal","Light eating"],ans:"Breaking the fast",hint:"Des- means 'un-' and ayuno means '___ing'."},
        {type:"fb",opts:["tomas","comes","quieres","bebes"],hint:"Asking what someone has/takes for breakfast.",s:"¿Qué {1} para el desayuno?",a:"tomas"},
        {type:"match",pairs:[{trg:"el desayuno",src:"breakfast"},{trg:"la tostada",src:"toast"},{trg:"el huevo",src:"egg"},{trg:"la mermelada",src:"jam"},{trg:"el cereal",src:"cereal"}]},
        {type:"mc",q:"A typical Spanish breakfast includes:",opts:["Eggs and bacon","Café con leche and tostadas","Pancakes and syrup","Rice and beans"],ans:"Café con leche and tostadas",hint:"Spanish breakfast is light. Think coffee and bread."},
        {type:"fb",opts:["ocho","pan","café","leche"],hint:"Fill in a time. Most people eat breakfast around this hour.",s:"Desayuno a las {1}.",a:"ocho"},
        {type:"mc",q:"Which is the main meal in Spain?",opts:["La cena (dinner)","El desayuno (breakfast)","La comida (lunch)","La merienda (snack)"],ans:"La comida (lunch)",hint:"Eaten around 2-3 PM, this is the biggest meal of the day."},
        {type:"drag_fill",hint:"Describe a typical Spanish morning meal.",s:"Para el {1}, tomo {2} con {3} y tostadas con {4}.",blanks:{"1":"desayuno","2":"café","3":"leche","4":"mermelada"},pool:["desayuno","café","leche","mermelada","cena","agua"]},
        {type:"fb",opts:["huevos","café","pan","tostadas"],hint:"Asking how someone wants these oval breakfast items prepared.",s:"¿Cómo quieres los {1}?",a:"huevos"},
        {type:"mc",q:"Translate: 'Quiero tostadas con tomate y aceite de oliva.'",opts:["I need bread with butter","I want toasted tomatoes with oil","I like toast with tomato sauce","I want toast with tomato and olive oil"],ans:"I want toast with tomato and olive oil",hint:"A classic Spanish breakfast. Tostada = ___."},
        {type:"fb",opts:["desayuno","desayunas","desayuna","desayunamos"],hint:"First person singular of desayunar.",s:"Yo {1} a las siete y media.",a:"desayuno"}
  ]},
  {id:"esp4l6",title:"En el Restaurante",icon:"🍽️",xp:15,board:true,steps:[
        {type:"intro",title:"En el Restaurante",desc:"Learn to order food, ask for the bill, and be polite at a restaurant.",goals:["Order food at a restaurant","Ask for the menu and the bill","Use me pone / me trae"]},
        {type:"teach",trg:"la carta",src:"the menu",pos:"noun",gender:"f",phonetic:"KAR-tah",note:"Feminine. Also called 'el menú'. La carta is more common in Spain.",example:"A: ¿Nos trae la carta, por favor?\nB: Sí, aquí tienen.",exampleSrc:"A: Could you bring us the menu, please?\nB: Yes, here you go.",funFact:"Menu (restaurant). Originally 'letter.' The menu is a 'letter'; listing what the restaurant writes to you. Spanish keeps both senses: carta = letter OR menu, context decides."},
        {type:"teach",trg:"pedir",src:"to order / to ask for",pos:"verb",gender:null,phonetic:"peh-DEER",note:"Stem-changing: pido, pides, pide, pedimos, piden (e→i).",example:"A: ¿Estáis listos para pedir?\nB: Sí, yo quiero la paella.",exampleSrc:"A: Are you ready to order?\nB: Yes, I want the paella.",funFact:"Spanish distinguishes 'pedir' (ask for something) from 'preguntar' (ask a question). 'Pedir un café' = order a coffee. 'Preguntar por el café' = ask about the coffee. English 'ask' collapses both."},
        {type:"teach",trg:"la cuenta",src:"the bill / check",pos:"noun",gender:"f",phonetic:"KWEN-tah",note:"Feminine. In Spain, you must ask for the bill. They won't bring it automatically.",example:"A: ¿Nos trae la cuenta, por favor?\nB: Ahora mismo.",exampleSrc:"A: Could you bring us the bill, please?\nB: Right away.",funFact:"Bill/check. From Latin 'computa' (counted things). Same root as 'computer.' 'La cuenta, por favor' is universal Spanish restaurant closing phrase."},
        {type:"teach",trg:"la ensalada",src:"the salad",pos:"noun",gender:"f",phonetic:"en-sah-LAH-dah",note:"Feminine. Ensalada mixta is a common starter in Spain.",example:"A: ¿Qué van a pedir?\nB: Una ensalada mixta para empezar.",exampleSrc:"A: What are you going to order?\nB: A mixed salad to start.",funFact:"Cognate with English 'salad'. Spanish and English share many Latin-derived words."},
        {type:"teach",trg:"la sopa",src:"the soup",pos:"noun",gender:"f",phonetic:"SOH-pah",note:"Feminine. Gazpacho is a famous cold soup from Andalusia.",example:"A: ¿Hay sopa del día?\nB: Sí, hoy tenemos sopa de verduras.",exampleSrc:"A: Is there a soup of the day?\nB: Yes, today we have vegetable soup.",funFact:"Soup. From Germanic 'suppa' (soaked bread), borrowed via Vulgar Latin. Sopas were originally bread soaked in broth before the broth became primary."},
        {type:"teach",trg:"de primero / de segundo",src:"for the first course / second course",pos:"noun",gender:null,phonetic:"deh pree-MEH-roh / seh-GOON-doh",note:"Spanish meals have courses: de primero (starter), de segundo (main), de postre (dessert).",example:"A: ¿Qué quiere de primero?\nB: De primero, la sopa. De segundo, el pescado.",exampleSrc:"A: What would you like for the first course?\nB: For the first course, soup. For second, fish.",funFact:"'For the first course / for the second course.' Restaurant ordering formula. 'De' marks the menu section. Spanish meals traditionally have primero (soup/salad), segundo (main), and postre (dessert)."},
        {type:"tip",title:"Restaurant Phrases",text:"Useful phrases:\n¿Nos trae la carta? = Can you bring the menu?\n¿Me pone un...? = Can I have a...? (Spain)\nPara mí, el/la... = For me, the...\nDe primero / de segundo / de postre\n¿Nos trae la cuenta? = Can we have the bill?\n\nTipping in Spain: not expected but 5-10% is appreciated.",icon:"🍽️"},
        {type:"mc",q:"How do you ask for the menu in Spain?",opts:["¿Nos trae la carta, por favor?","¿Dónde está el menú?","Quiero la carta","Dame la carta"],ans:"¿Nos trae la carta, por favor?",hint:"Use the polite form with '___ ___' (could you bring us)."},
        {type:"fb",opts:["primero","segundo","postre","carta"],hint:"This word indicates the first course of a meal.",s:"De {1}, quiero la sopa.",a:"primero"},
        {type:"match",pairs:[{trg:"la carta",src:"menu"},{trg:"la cuenta",src:"bill"},{trg:"la ensalada",src:"salad"},{trg:"la sopa",src:"soup"},{trg:"pedir",src:"to order"}]},
        {type:"mc",q:"In Spain, what happens with the bill?",opts:["It comes automatically","You must ask for it","You pay at the counter","There is no tipping"],ans:"You must ask for it",hint:"Spanish restaurants wait until you request la cuenta."},
        {type:"fb",opts:["Estáis","Somos","Tenemos","Queremos"],hint:"Asking 'are you (plural) ready?' uses estar, not ser.",s:"¿{1} listos para pedir?",a:"Estáis"},
        {type:"mc",q:"What is 'de segundo'?",opts:["the starter","the dessert","the main course","the drink"],ans:"the main course",hint:"Segundo means second. It's the second ___ after the starter."},
        {type:"drag_fill",hint:"Order a starter salad and a fish main course.",s:"De {1}, la {2}. De {3}, el {4}.",blanks:{"1":"primero","2":"ensalada","3":"segundo","4":"pescado"},pool:["primero","ensalada","segundo","pescado","postre","sopa"]},
        {type:"fb",opts:["cuenta","carta","sopa","ensalada"],hint:"You've finished eating and want to pay.",s:"¿Nos trae la {1}, por favor?",a:"cuenta"},
        {type:"mc",q:"Translate: 'Para mí, una ensalada mixta.'",opts:["The mixed salad is good","I want a mixed salad","A salad for everyone","For me, a mixed salad"],ans:"For me, a mixed salad",hint:"'Para mí' means 'for me'. A polite way to order."},
        {type:"fb",opts:["día","menú","primero","noche"],hint:"Asking if there is a soup of the ___. A daily special.",s:"¿Hay sopa del {1}?",a:"día"}
  ]},
  {id:"esp4l7",title:"Los Sabores",icon:"😋",xp:15,board:true,steps:[
        {type:"intro",title:"Los Sabores",desc:"Learn to describe food tastes and give opinions about meals.",goals:["Describe food flavors","Use está + adjective for food","Give opinions on dishes"]},
        {type:"teach",trg:"dulce",src:"sweet",pos:"noun",gender:"m",phonetic:"DOOL-seh",note:"Same form for masculine and feminine. El chocolate es dulce.",example:"A: ¿Cómo es el pastel?\nB: Está muy dulce. Me gusta.",exampleSrc:"A: How is the cake?\nB: It's very sweet. I like it.",funFact:"Sweet. Invariable for gender: el postre dulce, la fruta dulce. From Latin 'dulcis.' Same root as English 'dulcet.' Plural takes -s: dulces."},
        {type:"teach",trg:"salado",src:"salty",pos:"noun",gender:"m",phonetic:"sah-LAH-doh",note:"Masculine: salado. Feminine: salada. Agrees with the noun.",example:"A: ¿Qué tal la sopa?\nB: Está un poco salada.",exampleSrc:"A: How's the soup?\nB: It's a little salty.",funFact:"Salty. From 'sal' (salt). In Latin America, 'salado' also means 'unlucky'; an extension of 'salt as bad omen.' Context decides: food vs luck."},
        {type:"teach",trg:"picante",src:"spicy / hot",pos:"adj",gender:null,phonetic:"pee-KAHN-teh",note:"Same form for both genders. Very common in Mexican cuisine.",example:"A: ¿Te gusta la comida picante?\nB: No mucho. Prefiero la comida suave.",exampleSrc:"A: Do you like spicy food?\nB: Not much. I prefer mild food.",funFact:"Spicy hot. From 'picar' (to sting, prick). Literally 'stinging.' Different from 'caliente' (temperature hot). Crucial distinction when ordering food."},
        {type:"teach",trg:"rico / delicioso",src:"delicious",pos:"intj",gender:null,phonetic:"RREE-koh / deh-lee-see-OH-soh",note:"Rico/rica is informal. Delicioso/a is more formal. Both mean delicious.",example:"A: ¿Qué tal el desayuno?\nB: ¡Muy rico! Está muy bueno.",exampleSrc:"A: How's breakfast?\nB: Delicious! It's very good.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"está bueno / malo",src:"it tastes good / bad",pos:"intj",gender:null,phonetic:"ehs-TAH BWEH-noh / MAH-loh",note:"Use ESTAR (not ser) for how food tastes right now. Está bueno = it tastes good.",example:"A: ¿Está bueno el pescado?\nB: Sí, está muy bueno.",exampleSrc:"A: Is the fish good?\nB: Yes, it's very good.",funFact:"'Es bueno' = (character) good. 'Está bueno' = (taste/feel) good. Same adjective, different auxiliary = different meaning."},
        {type:"tip",title:"Ser vs Estar with Food",text:"SER = what it IS (permanent quality):\nLa paella es un plato español.\n(Paella is a Spanish dish.)\n\nESTAR = how it IS right now (condition/taste):\nLa paella está deliciosa.\n(The paella tastes delicious.)\n\nFor food opinions, almost always use ESTAR:\n¿Está bueno? ¿Está rico? ¿Está caliente?",icon:"📝"},
        {type:"teach",trg:"caliente",src:"hot (temperature)",pos:"adj",gender:null,phonetic:"kah-lee-EN-teh",note:"Same for both genders. For spicy hot, use 'picante'.",example:"A: ¡Cuidado! La sopa está muy caliente.\nB: Gracias. Espero un momento.",exampleSrc:"A: Careful! The soup is very hot.\nB: Thanks. I'll wait a moment.",funFact:"Hot (temperature). From Latin 'calentem.' Refers to temperature, NOT spicy. For spicy use 'picante.' Invariable for gender but agrees in number: calientes."},
        {type:"mc",q:"Which verb do you use to describe how food tastes?",opts:["estar","ser","tener","haber"],ans:"estar",hint:"Food taste is a current condition, not a permanent trait."},
        {type:"fb",opts:["está","es","tiene","hay"],hint:"Describing how the soup tastes right now.",s:"La sopa {1} un poco salada.",a:"está"},
        {type:"match",pairs:[{trg:"dulce",src:"sweet"},{trg:"salado",src:"salty"},{trg:"picante",src:"spicy"},{trg:"caliente",src:"hot"},{trg:"rico",src:"delicious"}]},
        {type:"mc",q:"'¡Está riquísima!' means:",opts:["It's very expensive!","It's absolutely delicious!","She is very rich!","It's extremely spicy!"],ans:"It's absolutely delicious!",hint:"Rico normally means 'rich', but applied to food it shifts meaning. The -ísima suffix intensifies to the extreme."},
        {type:"fb",opts:["picante","caliente","dulce","salada"],hint:"Asking about spicy food, common in Mexican cuisine.",s:"¿Te gusta la comida {1}?",a:"picante"},
        {type:"mc",q:"Which sentence is correct?",opts:["La paella tiene deliciosa","La paella es deliciosa","La paella está deliciosa","La paella hay deliciosa"],ans:"La paella está deliciosa",hint:"How it tastes right now = ___ar. Ser also works for general quality, but ___ar is preferred."},
        {type:"drag_fill",hint:"Both describe current taste. Use estar for both.",s:"La sopa {1} muy {2} pero el postre {3} demasiado {4}.",blanks:{"1":"está","2":"rica","3":"está","4":"dulce"},pool:["está","rica","está","dulce","es","salada"]},
        {type:"fb",opts:["está","es","tiene","hay"],hint:"The coffee IS hot right now. Current state = estar.",s:"¡Cuidado! El café {1} muy caliente.",a:"está"},
        {type:"mc",q:"What is the difference between 'caliente' and 'picante'?",opts:["Caliente = warm, picante = burning hot","Caliente = spicy, picante = temperature","They mean the same thing","Caliente = temperature, picante = spicy flavor"],ans:"Caliente = temperature, picante = spicy flavor",hint:"One is about heat you feel, the other about heat you taste."},
        {type:"fb",opts:["está","es","tiene","hay"],hint:"Describing how the ice cream tastes right now.",s:"El helado {1} muy dulce.",a:"está"}
  ]},
  {id:"esp4l7b",title:"La paella de Carmen",icon:"🥘",xp:10,board:true,steps:[
        {type:"intro",title:"La paella de Carmen",desc:"Carmen takes Verumius to a restaurant in Madrid. He tries paella for the first time. It does not go quite as expected.",goals:["See food vocabulary in real conversation","Watch Verumius order and react to food","Enjoy the story"]},
        {type:"story",speaker:"narrator",mood:"excited",art:"es-unit-04-scene-01",trg:"Carmen lleva a Verumius a un restaurante. Él tiene mucha hambre. La carta es grande y Verumius no sabe qué pedir.",src:"Carmen takes Verumius to a restaurant. He is very hungry. The menu is big and Verumius does not know what to order."},
        {type:"story",speaker:"verumius",mood:"nervous",art:"es-unit-04-scene-01",trg:"Carmen, tengo hambre. ¿Qué quieres comer? Yo quiero... la carta.",src:"Carmen, I'm hungry. What do you want to eat? I want... the menu."},
        {type:"story",speaker:"carmen",mood:"laughing",art:"es-unit-04-scene-02",trg:"¡Verumius! La carta es el menú, no la comida. ¿Quieres la paella?",src:"Verumius! The menu is the menu, not the food. Do you want the paella?"},
        {type:"story",speaker:"verumius",mood:"eager",art:"es-unit-04-scene-02",trg:"Sí, por favor. De primero, quiero una ensalada. De segundo, ¡quiero la paella!",src:"Yes, please. For the first course, I want a salad. For the second, I want the paella!"},
        {type:"story",speaker:"verumius",mood:"amazed",art:"es-unit-04-scene-03",trg:"¡Carmen! ¡La paella está muy rica! Tiene arroz, pollo y... ¿verduras?",src:"Carmen! The paella is very delicious! It has rice, chicken and... vegetables?"},
        {type:"story",speaker:"carmen",mood:"happy",art:"es-unit-04-scene-03",trg:"Sí, y tiene tomate. ¿Está buena? ¡En Roma no hay paella!",src:"Yes, and it has tomato. Is it good? In Rome there is no paella!"}
  ]},
  {id:"esp4l8",title:"¿Qué Comemos?",icon:"🛒",xp:15,board:true,steps:[
        {type:"intro",title:"¿Qué Comemos?",desc:"Put it all together: order meals, describe food, and express preferences.",goals:["Order a complete meal","Combine food vocabulary with opinions","Use gustar, querer, estar naturally"]},
        {type:"mc",q:"How do you say 'I'm thirsty'?",opts:["Tengo sed","Estoy sed","Soy sed","Tengo sedo"],ans:"Tengo sed",hint:"Spanish uses 'to have thirst', not 'to be thirsty'."},
        {type:"drag_fill",hint:"Fresas is plural (gustan). Limón is singular (gusta).",s:"Me {1} las fresas pero no me {2} el limón.",blanks:{"1":"gustan","2":"gusta"},pool:["gustan","gusta","gusto","gustas"]},
        {type:"match",pairs:[{trg:"el desayuno",src:"breakfast"},{trg:"la carne",src:"meat"},{trg:"el pescado",src:"fish"},{trg:"la cuenta",src:"bill"},{trg:"la ensalada",src:"salad"},{trg:"la verdura",src:"the vegetable"}]},
        {type:"mc",q:"You want to order the fish. What do you say?",opts:["Yo quiere el pescado","Para mí, el pescado, por favor","Me pongo el pescado","El pescado me gusta pedir"],ans:"Para mí, el pescado, por favor",hint:"'___ mí' + the item is the polite way to order."},
        {type:"drag_fill",hint:"Name the first course and the second course.",s:"De {1}, la sopa. De {2}, el pollo con arroz.",blanks:{"1":"primero","2":"segundo"},pool:["primero","segundo","postre","carta"]},
        {type:"drag_fill",hint:"Ask the waiter to bring the bill politely.",s:"¿Nos {1} la {2}, por {3}?",blanks:{"1":"trae","2":"cuenta","3":"favor"},pool:["trae","cuenta","favor","pone","carta","gracias"]},
        {type:"mc",q:"Which is correct?",opts:["El café tiene caliente","El café es caliente","El café está caliente","El café está picante"],ans:"El café está caliente",hint:"Temperature of a drink right now = ___ar + ___."},
        {type:"fb",opts:["está","es","tiene","hay"],hint:"Describing how the paella tastes. Current condition.",s:"La paella {1} muy rica.",a:"está"},
        {type:"mc",q:"Translate: 'Quiero un zumo de naranja y tostadas con mermelada.'",opts:["I need a naranja juice and toast","I want a tomato juice and toast with butter","I like orange juice with bread","I want an orange juice and toast with jam"],ans:"I want an orange juice and toast with jam",hint:"Zumo de naranja = ___ ___. Mermelada = ___."},
        {type:"drag_fill",hint:"Express hunger and order a classic rice dish.",s:"Tengo mucha {1}. {2} comer {3} con {4}.",blanks:{"1":"hambre","2":"Quiero","3":"arroz","4":"pollo"},pool:["hambre","Quiero","arroz","pollo","sed","Tengo"]},
        {type:"mc",q:"What is NOT a first course (de primero)?",opts:["el pollo con arroz","la sopa","la ensalada","la sopa del día"],ans:"el pollo con arroz",hint:"Chicken with rice is a main dish (de segundo), not a starter."},
        {type:"fb",opts:["pone","trae","da","tiene"],hint:"A polite way to order in Spain. Literally: 'Do you put me...?'",s:"¿Me {1} un café con leche?",a:"pone"},
        {type:"match",pairs:[{trg:"dulce",src:"sweet"},{trg:"salado",src:"salty"},{trg:"picante",src:"spicy"},{trg:"caliente",src:"hot"},{trg:"la carta",src:"menu"}]},
        {type:"mc",q:"Which expression uses 'tener' in Spanish but 'to be' in English?",opts:["Tengo un libro (I have a book)","Tengo hambre (I'm hungry)","Tengo que estudiar (I have to study)","Tengo pan (I have bread)"],ans:"Tengo hambre (I'm hungry)",hint:"In Spanish you 'have hunger', in English you 'are ___'."},
        {type:"drag_fill",hint:"Order a two-course meal: salad starter, meat main.",s:"De {1}, una {2} mixta. De {3}, {4} con patatas.",blanks:{"1":"primero","2":"ensalada","3":"segundo","4":"carne"},pool:["primero","ensalada","segundo","carne","postre","sopa"]},
        {type:"mc",q:"A friend says '¡Está riquísima!' about the paella. This means:",opts:["She's very rich","It's extremely expensive","It's absolutely delicious","It's very spicy"],ans:"It's absolutely delicious",hint:"Riquísima is the superlative of rico. Applied to food it shifts from 'rich' to a taste compliment."},
        {type:"fb",opts:["pone","trae","quiero","gusta"],hint:"A polite way to order in Spain, meaning 'can you give me'.",s:"¿Me {1} un café, por favor?",a:"pone"}
  ]},
  {id:"esv2_u4l_essential",title:"Vocabulario Esencial A1",icon:"📚",xp:20,board:true,steps:[
    {type:"intro",title:"Vocabulario Esencial A1",desc:"Consolidate core A1 vocabulary: everyday places, formal address, family, fruit, and three high-frequency irregular verbs.",goals:["Name places: school, university, restaurant","Distinguish tú (informal) from usted (formal)","Use hacer, querer, and saber correctly","Talk about family and fruit"]},
    {type:"teach",trg:"la familia",src:"family",pos:"noun",gender:"f",phonetic:"lah fah-MEE-lyah",note:"Feminine noun.\nUsed for both immediate and extended family.",example:"A: ¿Tienes una familia grande?\nB: Sí, tengo tres hermanos y dos hermanas.",exampleSrc:"A: Do you have a big family?\nB: Yes, I have three brothers and two sisters.",funFact:"From Latin familia (household). In Spanish-speaking cultures, the family circle often includes godparents (padrinos) as core members."},
    {type:"teach",trg:"el restaurante",src:"restaurant",pos:"noun",gender:"m",phonetic:"rres-tow-RAHN-teh",note:"Masculine noun. Cognate of English 'restaurant'.",example:"A: ¿Vamos al restaurante esta noche?\nB: Sí, vamos a las ocho.",exampleSrc:"A: Shall we go to the restaurant tonight?\nB: Yes, let's go at eight.",funFact:"Borrowed from French restaurant in the 19th century. The same word is used across the Spanish-speaking world."},
    {type:"teach",trg:"la universidad",src:"university",pos:"noun",gender:"f",phonetic:"oo-nee-ber-see-DAHD",note:"Feminine noun. Words ending in -dad are always feminine.",example:"A: ¿Estudias en la universidad?\nB: Sí, estudio en la Universidad de Madrid.",exampleSrc:"A: Do you study at the university?\nB: Yes, I study at the University of Madrid.",funFact:"From Latin universitas. Words ending in -dad are always feminine in Spanish, making them easy to identify."},
    {type:"teach",trg:"la escuela",src:"school",pos:"noun",gender:"f",phonetic:"lah ehs-KWEH-lah",note:"Feminine noun. Refers to primary school. Secondary school is el instituto.",example:"A: ¿A qué hora termina la escuela?\nB: La escuela termina a las tres.",exampleSrc:"A: What time does school finish?\nB: School finishes at three.",funFact:"From Latin schola, from Greek skhole. In Spain, primary school runs from age 6 to 12."},
    {type:"teach",trg:"la fruta",src:"fruit",pos:"noun",gender:"f",phonetic:"lah FROO-tah",note:"Feminine noun. Collective term for all fruit.",example:"A: ¿Comes mucha fruta?\nB: Sí, como fruta todos los dias.",exampleSrc:"A: Do you eat a lot of fruit?\nB: Yes, I eat fruit every day.",funFact:"From Latin fructus. In Spanish, 'la fruta' (collective) is different from 'la fruta / el fruto' (one piece), though in everyday speech 'fruta' covers both."},
    {type:"teach",trg:"usted",src:"you (formal)",pos:"pron",gender:null,phonetic:"oos-TED",note:"Formal 'you' for strangers, elders, and professional settings.\nAbbreviated Ud. or Vd.",example:"A: Buenos dias. ¿Cómo se llama usted?\nB: Me llamo Garcia. ¿Y usted?",exampleSrc:"A: Good morning. What is your name (formal)?\nB: My name is Garcia. And yours?",funFact:"Usted comes from 'vuestra merced' (your grace). Over centuries it shortened to usted. Despite meaning 'you', it uses third-person verb forms."},
    {type:"teach",trg:"hacer",src:"to do / to make",pos:"verb",gender:null,phonetic:"ah-SEHR",note:"Highly irregular. Yo form: hago (not haco).\nOther forms are regular: haces, hace, hacemos, hacen.",example:"A: ¿Qué haces en casa?\nB: Hago la comida cada día.",exampleSrc:"A: What do you do at home?\nB: I make the food every day.",funFact:"Hago is one of the most irregular yo-forms in Spanish. It belongs to a group of verbs (poner, traer, salir) with unpredictable yo stems."},
    {type:"teach",trg:"querer",src:"to want",pos:"verb",gender:null,phonetic:"keh-REHR",note:"Stem-changing e to ie. Yo: quiero. Tu: quieres. El: quiere.\nNosotros: queremos (no change). Ellos: quieren.",example:"A: ¿Qué quieres hacer hoy?\nB: Quiero ir al restaurante.",exampleSrc:"A: What do you want to do today?\nB: I want to go to the restaurant.",funFact:"Querer also means 'to love' when used with people: Te quiero = I love you. Context always makes the meaning clear."},
    {type:"teach",trg:"saber",src:"to know (facts/how to)",pos:"verb",gender:null,phonetic:"sah-BEHR",note:"Irregular yo: sé. Other forms regular: sabes, sabe, sabemos, saben.\nSaber = knowing facts or how to do something.",example:"A: ¿Sabes hablar español?\nB: No, no sé. Es muy difícil.",exampleSrc:"A: Do you know how to speak Spanish?\nB: No, I don't know. It's very difficult.",funFact:"Spanish has two verbs for 'to know': saber (facts, skills, how to) and conocer (people, places). This distinction does not exist in English."},
    {type:"tip",title:"Saber vs Conocer",text:"Both mean 'to know' but are NOT interchangeable:\n\nsaber = know a fact or know how to do something:\n¿Sabes su nombre? (Do you know her name?)\n¿Sabes nadar? (Do you know how to swim?)\n\nconocer = know/be acquainted with a person or place:\n¿Conoces Madrid? (Do you know Madrid?)\nConozco a Maria. (I know Maria.)\n\nTip: if you can replace 'know' with 'know how to' or 'know that', use saber.",icon:"💡"},
    {type:"mc",q:"¿Dónde estudias?",opts:["En la universidad","En el restaurante","En la fruta","En la familia"],ans:"En la universidad",hint:"Choose the place where people go to study at degree level."},
    {type:"fb",opts:["usted","tú","él","yo"],hint:"You are addressing a professor you have never met. Use the formal form.",s:"Buenos dias, profesor. ¿Cómo está {1}?",a:"usted"},
    {type:"mc",q:"¿Cómo se dice 'to make dinner' in Spanish?",opts:["querer la cena","hacer la cena","tener la cena","saber la cena"],ans:"hacer la cena",hint:"'To do' or 'to make' something = this irregular verb."},
    {type:"fb",opts:["sé","sabes","sabe","sabemos"],hint:"First-person singular of saber. Remember: this yo-form is irregular.",s:"No {1} cocinar. ¿Me enseñas?",a:"sé"},
    {type:"match",pairs:[{trg:"la familia",src:"family"},{trg:"el restaurante",src:"restaurant"},{trg:"la universidad",src:"university"},{trg:"la escuela",src:"school"},{trg:"la fruta",src:"fruit"}]},
    {type:"mc",q:"¿Qué significa 'usted'?",opts:["you (informal)","he / she","you (formal)","I"],ans:"you (formal)",hint:"This pronoun is used with strangers, elders, and in professional contexts."},
    {type:"fb",opts:["querer","hacer","saber","tener"],hint:"This verb means 'to want'. It stem-changes e to ie.",s:"¿Cuál es el infinitivo de 'quiero'?",a:"querer"},
    {type:"mc",q:"Select the correct form: 'Ella ___ hablar inglés.'",opts:["saben","sé","sabes","sabe"],ans:"sabe",hint:"Ella is third-person singular. Saber is regular in all forms except yo."},
    {type:"fb",opts:["hago","haces","hace","hacemos"],hint:"First-person singular of hacer. The yo form is irregular.",s:"Yo {1} la comida cada día.",a:"hago"},
    {type:"mc",q:"Choose the correct verb: '¿___ a Carmen?' (Do you know Carmen?)",opts:["Conoces","Tienes","Quieres","Sabes"],ans:"Conoces",hint:"You are acquainted with a person, not asking about a fact. Use the verb for personal acquaintance."},
    {type:"fb",opts:["escuela","universidad","restaurante","familia"],hint:"This is where young children go to learn. Not a university.",s:"Los niños van a la {1} por la mañana.",a:"escuela"},
    {type:"match",pairs:[{trg:"hacer",src:"to do / to make"},{trg:"querer",src:"to want"},{trg:"saber",src:"to know (facts)"}]},
    {type:"mc",q:"¿Qué quieres comer? Complete the reply: '___ ir al restaurante.'",opts:["Hago","Quiero","Sabes","Sé"],ans:"Quiero",hint:"Expressing a personal desire uses the yo form of querer."},
    {type:"fb",opts:["fruta","familia","escuela","universidad"],hint:"A collective noun for apples, oranges, strawberries, and similar items.",s:"Como mucha {1}: manzanas, naranjas y fresas.",a:"fruta"},
    {type:"mc",q:"'Usted' uses which verb form?",opts:["yo form","tú form","él/ella form","nosotros form"],ans:"él/ella form",hint:"Even though usted means 'you', it is grammatically third-person singular."},
    {type:"fb",opts:["hacer","querer","saber","tener"],hint:"Use this verb when you know a fact or know how to do something.",s:"¿{1} hablar español?",a:"saber"}
  ]}
]};
